import{_ as t,o as a,c as i,ad as s}from"./chunks/framework.DdcUsuRQ.js";const m=JSON.parse('{"title":"HSV","description":"The cylindrical hue, saturation, value re-parameterisation of sRGB used by the iridis picker. Sector-based conversion math and why no pipeline primitive ships.","frontmatter":{"title":"HSV","description":"The cylindrical hue, saturation, value re-parameterisation of sRGB used by the iridis picker. Sector-based conversion math and why no pipeline primitive ships.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/hsv"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/hsv"}],["meta",{"property":"og:title","content":"HSV: iridis"}],["meta",{"property":"og:description","content":"The cylindrical hue, saturation, value re-parameterisation of sRGB used by the iridis picker. Sector-based conversion math and why no pipeline primitive ships."}],["meta",{"name":"twitter:title","content":"HSV: iridis"}],["meta",{"name":"twitter:description","content":"The cylindrical hue, saturation, value re-parameterisation of sRGB used by the iridis picker. Sector-based conversion math and why no pipeline primitive ships."}],["meta",{"name":"description","content":"The cylindrical hue, saturation, value re-parameterisation of sRGB used by the iridis picker. Sector-based conversion math and why no pipeline primitive ships."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"HSV\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/hsv\\"}]}"]]},"headers":[],"relativePath":"reference/hsv.md","filePath":"reference/hsv.md","lastUpdated":1779033869000}'),n={name:"reference/hsv.md"};function r(o,e,p,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="hsv" tabindex="-1">HSV <a class="header-anchor" href="#hsv" aria-label="Permalink to &quot;HSV&quot;">​</a></h1><p>HSV (hue, saturation, value) is a cylindrical re-parameterisation of sRGB. It exists because flat RGB sliders are a poor interface for picking a color by eye, moving along the hue axis at constant saturation and value is the natural action a human takes when they want &quot;the same color, but more orange&quot;.</p><h2 id="coordinates" tabindex="-1">Coordinates <a class="header-anchor" href="#coordinates" aria-label="Permalink to &quot;Coordinates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Channel</th><th>Range</th><th>Meaning</th></tr></thead><tbody><tr><td>H (hue)</td><td><code>[0, 360)</code> degrees</td><td>angle around the color wheel, 0 = red, 120 = green, 240 = blue</td></tr><tr><td>S (saturation)</td><td><code>[0, 1]</code> or <code>[0, 100]</code> percent</td><td>distance from the central grey axis at the current hue and value</td></tr><tr><td>V (value)</td><td><code>[0, 1]</code> or <code>[0, 100]</code> percent</td><td>maximum of the three RGB channels at that point</td></tr></tbody></table><p>HSV is not perceptually uniform. Equal steps in H or S do not produce equal perceived steps in color. It is also not a wide-gamut or HDR-aware space. It is a convenient projection of sRGB.</p><h2 id="conversion-to-rgb" tabindex="-1">Conversion to RGB <a class="header-anchor" href="#conversion-to-rgb" aria-label="Permalink to &quot;Conversion to RGB&quot;">​</a></h2><p>The standard algorithm partitions the hue circle into six 60-degree sectors and selects which two of the three RGB channels are at extremes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>H&#39; = H / 60</span></span>
<span class="line"><span>i  = floor(H&#39;) mod 6</span></span>
<span class="line"><span>f  = H&#39; − floor(H&#39;)</span></span>
<span class="line"><span>p  = V · (1 − S)</span></span>
<span class="line"><span>q  = V · (1 − f · S)</span></span>
<span class="line"><span>t  = V · (1 − (1 − f) · S)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>i = 0:  (R, G, B) = (V, t, p)</span></span>
<span class="line"><span>i = 1:  (R, G, B) = (q, V, p)</span></span>
<span class="line"><span>i = 2:  (R, G, B) = (p, V, t)</span></span>
<span class="line"><span>i = 3:  (R, G, B) = (p, q, V)</span></span>
<span class="line"><span>i = 4:  (R, G, B) = (t, p, V)</span></span>
<span class="line"><span>i = 5:  (R, G, B) = (V, p, q)</span></span></code></pre></div><p>The result is gamma-corrected sRGB. The reverse direction reads the maximum and minimum of the three channels: V = max, S = (max − min) / max, and H comes from which channel held the maximum.</p><h2 id="math-primitives" tabindex="-1">Math primitives <a class="header-anchor" href="#math-primitives" aria-label="Permalink to &quot;Math primitives&quot;">​</a></h2><p><span class="iridis-brand">iridis</span> does not export an <code>hsvToRgb</code> math primitive. HSV exists in <span class="iridis-brand">iridis</span> as a picker-side concern, not a pipeline concern. Conversions live inline in the picker component and round-trip through hex on every change.</p><p>The pipeline equivalent for an analogous cylindrical space is <code>hslToRgb</code> and <code>rgbToHsl</code> (<code>packages/core/src/math/HslToRgb.ts</code>, <code>packages/core/src/math/RgbToHsl.ts</code>), which use HSL, closely related but with a different definition of the lightness axis.</p><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><ul><li><code>IridisPicker.vue</code> (<code>docs/.vitepress/theme/components/IridisPicker.vue</code>) holds H, S, V as the canonical state of the picker. The visual square shows S × V at the current H, the strip below shows H, and every numeric tab (HEX, RGB, HSV, CMYK, OKLCH) reads from those three refs.</li><li>The picker emits a hex string on every edit. The pipeline never sees HSV; it sees the hex.</li></ul>`,14)])])}const u=t(n,[["render",r]]);export{m as __pageData,u as default};
